def är_heltal(inmatning):
  try:
    int(inmatning)
    return True
  except ValueError:
    print("Inte en siffra försök igen.")
    return False


def meny():
  val = 0
  while val != 2:
    print("Meny\n1. Val 1.\n2. Avsluta.")
    val = input("Vad vill du göra?")
    while not är_heltal(val):
      val = input("Vad vill du göra?")

    val = int(val)
    if val == 1:
      print("Du valde 1.\n")

    elif val ==2:
      print("Programmet avslutas")

    else:
       print("Fel siffra, välj igen.")

meny()
